using System.ComponentModel;
using System.Text;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using OpenAI;

// ── Configuration ──────────────────────────────────────────────────────
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// ── DI & services ─────────────────────────────────────────────────────
var services = new ServiceCollection();
services.AddLogging(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning));

services.AddChatClient(builder =>
    builder.UseOpenAIChatClient(modelId, new OpenAIClient(apiKey)));

var sp = services.BuildServiceProvider();
var chatClient = sp.GetRequiredService<IChatClient>();
var loggerFactory = sp.GetRequiredService<ILoggerFactory>();

// ── Tools ─────────────────────────────────────────────────────────────
var notebook = new Notebook();
var tools = new List<AITool>
{
    AIFunctionFactory.Create(WebSearchTool.SearchAsync, nameof(WebSearchTool.SearchAsync)),
    AIFunctionFactory.Create(notebook.SaveNote, nameof(notebook.SaveNote)),
    AIFunctionFactory.Create(notebook.GetNotes, nameof(notebook.GetNotes)),
};

// ── Agent ─────────────────────────────────────────────────────────────
const string instructions = """
    You are a research assistant. Your job is to research a topic by:
    1. Searching the web for relevant information using the SearchAsync tool.
    2. Saving key findings as notes using the SaveNote tool.
    3. After gathering enough information, retrieving your notes with GetNotes.
    4. Producing a clear, well-structured summary of your findings.

    Always search for at least 2-3 different queries to get broad coverage.
    Save the most important facts and cite sources. End with a summary.
    """;

var agent = new ChatClientAgent(
    chatClient,
    instructions: instructions,
    name: "ResearchAgent",
    description: "Researches a topic using web search and note-taking tools",
    tools: tools,
    loggerFactory: loggerFactory);

// ── Run ───────────────────────────────────────────────────────────────
Console.WriteLine("🔬 Research Agent");
Console.WriteLine("─────────────────────────────────────");
Console.Write("Enter a research topic (or press Enter for default): ");
var topic = Console.ReadLine();
if (string.IsNullOrWhiteSpace(topic))
{
    topic = "Recent advances in quantum computing";
}

Console.WriteLine($"\n📋 Researching: {topic}\n");

var runOptions = new ChatClientAgentRunOptions(
    new ChatOptions { Temperature = 0f, MaxOutputTokens = 4096 })
{
    ModelReasoningLevel = ChatReasoningLevel.None,
};

var response = await agent.RunAsync(
    $"Please research the following topic and provide a comprehensive summary: {topic}",
    options: runOptions);

Console.WriteLine("─────────────────────────────────────");
Console.WriteLine("📝 Research Summary:");
Console.WriteLine("─────────────────────────────────────");
Console.WriteLine(response.Text);
Console.WriteLine("─────────────────────────────────────");
Console.WriteLine($"\n📓 Notes collected: {notebook.Count}");

// ── Web Search Tool ───────────────────────────────────────────────────
static class WebSearchTool
{
    private static readonly HttpClient s_http = new();

    [Description("Search the web for information on a given query. Returns a list of results with titles, URLs, and snippets.")]
    public static async Task<string> SearchAsync(
        [Description("The search query string")] string query,
        CancellationToken cancellationToken = default)
    {
        Console.WriteLine($"  🔍 Searching: \"{query}\"");

        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

            var json = await s_http.GetStringAsync(url, cancellationToken);
            using var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new StringBuilder();

            // Abstract / instant answer
            var abstractText = root.GetProperty("AbstractText").GetString();
            var abstractSource = root.GetProperty("AbstractSource").GetString();
            var abstractUrl = root.GetProperty("AbstractURL").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                results.AppendLine($"## Summary from {abstractSource}");
                results.AppendLine(abstractText);
                results.AppendLine($"Source: {abstractUrl}");
                results.AppendLine();
            }

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                var count = 0;
                foreach (var item in topics.EnumerateArray())
                {
                    if (count >= 8) break;
                    var text = item.TryGetProperty("Text", out var t) ? t.GetString() : null;
                    var itemUrl = item.TryGetProperty("FirstURL", out var u) ? u.GetString() : null;
                    if (!string.IsNullOrWhiteSpace(text))
                    {
                        results.AppendLine($"- {text}");
                        if (!string.IsNullOrWhiteSpace(itemUrl))
                            results.AppendLine($"  URL: {itemUrl}");
                        count++;
                    }
                }
            }

            var output = results.ToString();
            return string.IsNullOrWhiteSpace(output)
                ? $"No detailed results found for \"{query}\". Try rephrasing the query."
                : output;
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }
}

// ── Notebook Tool ─────────────────────────────────────────────────────
sealed class Notebook
{
    private readonly List<(string Topic, string Content)> _notes = [];

    public int Count => _notes.Count;

    [Description("Save a research note with a topic label and content. Use this to record important findings during research.")]
    public string SaveNote(
        [Description("A short topic label for the note")] string topic,
        [Description("The content of the note — facts, quotes, or observations")] string content)
    {
        _notes.Add((topic, content));
        Console.WriteLine($"  📓 Note saved: \"{topic}\"");
        return $"Note #{_notes.Count} saved under \"{topic}\".";
    }

    [Description("Retrieve all saved research notes. Use this before writing the final summary to review what you've collected.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        for (var i = 0; i < _notes.Count; i++)
        {
            var (topic, content) = _notes[i];
            sb.AppendLine($"### Note #{i + 1}: {topic}");
            sb.AppendLine(content);
            sb.AppendLine();
        }

        return sb.ToString();
    }
}

